const webhook = $('Webhook1').first().json;
const leadData = $json;

if (leadData.facebook_lead_id) {
  return [{ json: leadData }];
}

if (leadData.error) {
  throw new Error('Meta Graph API error: ' + (leadData.error.message || JSON.stringify(leadData.error)));
}

const normalize = (value = '') => String(value)
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .toLowerCase()
  .trim();

const firstValue = (item) => Array.isArray(item?.values) ? (item.values[0] || '') : (item?.values || '');
const fieldData = Array.isArray(leadData.field_data) ? leadData.field_data : [];

if (!fieldData.length) {
  throw new Error('Lead payload without field_data');
}

const normalizedFields = fieldData.map((item) => ({
  key: normalize(item.name).replace(/[^a-z0-9]+/g, ' ').trim(),
  value: String(firstValue(item) || '').trim(),
}));

const findField = (...patterns) => {
  const normalizedPatterns = patterns.map((pattern) => normalize(pattern).replace(/[^a-z0-9]+/g, ' ').trim());
  const match = normalizedFields.find((field) => normalizedPatterns.some((pattern) => field.key.includes(pattern)));
  return match?.value || '';
};

const titleCase = (value = '') => String(value)
  .toLowerCase()
  .replace(/_/g, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .split(' ')
  .filter(Boolean)
  .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
  .join(' ');

const normalizeProfile = (value = '') => {
  const key = normalize(value).replace(/[^a-z0-9]+/g, ' ').trim();
  const profileMap = {
    distribuidora: 'Distribuidora',
    representante: 'Representante',
    lojista: 'Lojista',
    oficina: 'Oficina',
    revenda: 'Revenda',
    autopecas: 'Autopecas',
    'auto pecas': 'Autopecas',
  };
  return profileMap[key] || titleCase(value);
};

const normalizeVolume = (value = '') => {
  const key = normalize(value).replace(/[^a-z0-9]+/g, '');
  if (key.includes('abaixode2000')) return 'Abaixo de 2.000';
  if (key.includes('entre2000e4000')) return 'Entre 2.000 e 4.000';
  if (key.includes('entre4000e10000')) return 'Entre 4.000 e 10.000';
  if (key.includes('acimade10000')) return 'Acima de 10.000';
  return titleCase(value);
};

const telefone = findField('telefone', 'celular', 'whatsapp');
const nome = findField('nome');
const email = findField('email');
const perfil = normalizeProfile(findField('perfil', 'negocio'));
const volumeFaixa = normalizeVolume(findField('estimativa media de compra mensal', 'compra mensal', 'volume'));
const cnpjRaw = findField('cnpj');
const estadoEnvio = findField('estado', 'envio');

const change = webhook.body?.entry?.[0]?.changes?.[0]?.value || {};

return [{
  json: {
    facebook_lead_id: leadData.id || change.leadgen_id || '',
    form_id: change.form_id || '',
    page_id: change.page_id || webhook.body?.entry?.[0]?.id || '',
    nome,
    email,
    telefone_raw: telefone,
    perfil,
    volume_faixa: volumeFaixa,
    cnpj_raw: cnpjRaw,
    estado_envio: estadoEnvio,
  }
}];

const rawPhone = $json.telefone_raw || '';
let phone = rawPhone.replace(/\D/g, '');

if (phone.length === 13 && phone.startsWith('55')) {
  // OK: 55 + DDD(2) + num(9)
} else if (phone.length === 12 && phone.startsWith('55')) {
  // Missing 9: 55+DDD+8dig
  phone = phone.slice(0, 4) + '9' + phone.slice(4);
} else if (phone.length === 11 && phone.startsWith('0')) {
  // 0+DDD+9+num
  phone = '55' + phone.slice(1);
} else if (phone.length === 11) {
  // DDD+9+num
  phone = '55' + phone;
} else if (phone.length === 10) {
  // DDD+num (missing 9)
  phone = '55' + phone.slice(0, 2) + '9' + phone.slice(2);
} else if (phone.length === 12 && phone.startsWith('0')) {
  // 0+DDD+9+num (extra 0)
  phone = '55' + phone.slice(1);
} else {
  phone = 'INVALID_' + rawPhone;
}

return [{
  json: {
    ...$json,
    telefone: phone,
    phone_valid: !phone.startsWith('INVALID')
  }
}];

const cnpjRaw = $json.cnpj_raw || '';
const cnpj = cnpjRaw.replace(/\D/g, '');
return [{
  json: {
    ...$json,
    cnpj: cnpj,
    cnpj_length: cnpj.length
  }
}];

const extract = $('Extract Form Fields').first().json;
const phone = $('Normalize Phone').first().json;
const cnpjData = $('Clean CNPJ').first().json;
const enrich = $('02A Company Enrich').first().json;

// Volume mapping
const volumeMap = {
  'Abaixo de 2.000': 1500,
  'Entre 2.000 e 4.000': 3000,
  'Entre 4.000 e 10.000': 7000,
  'Acima de 10.000': 12000
};
const volume_numerico = volumeMap[extract.volume_faixa] || 0;

// State to UF mapping
const stateMap = {
  'acre': 'AC', 'alagoas': 'AL', 'amapa': 'AP', 'amazonas': 'AM',
  'bahia': 'BA', 'ceara': 'CE', 'distrito federal': 'DF',
  'espirito santo': 'ES', 'goias': 'GO', 'maranhao': 'MA',
  'mato grosso': 'MT', 'mato grosso do sul': 'MS',
  'minas gerais': 'MG', 'para': 'PA', 'paraiba': 'PB',
  'parana': 'PR', 'pernambuco': 'PE', 'piaui': 'PI',
  'rio de janeiro': 'RJ', 'rio grande do norte': 'RN',
  'rio grande do sul': 'RS', 'rondonia': 'RO', 'roraima': 'RR',
  'santa catarina': 'SC', 'sao paulo': 'SP', 'sergipe': 'SE',
  'tocantins': 'TO',
  // Accented versions
  'amapá': 'AP', 'ceará': 'CE', 'espírito santo': 'ES',
  'goiás': 'GO', 'maranhão': 'MA', 'paraná': 'PR',
  'piauí': 'PI', 'rondônia': 'RO', 'são paulo': 'SP'
};
const rawState = (extract.estado_envio || '').trim();
let estado_uf = stateMap[rawState.toLowerCase()] || rawState.toUpperCase();
// If already a 2-letter code, use as-is
if (estado_uf.length > 2) estado_uf = rawState.substring(0, 2).toUpperCase();

// N/NE regions
const NNE = ['AC','AM','AP','PA','RO','RR','TO','AL','BA','CE','MA','PB','PE','PI','RN','SE'];
const isNNE = NNE.includes(estado_uf);

// Classification logic
let path, path_reason;
if (volume_numerico < 4000) {
  path = 2;
  path_reason = 'Volume < R$4000 - distribuidor';
} else if (isNNE) {
  path = 3;
  path_reason = 'Qualificado: volume >= 4k + N/NE';
} else {
  path = 2;
  path_reason = 'Volume >= 4k mas fora N/NE - distribuidor';
}

const path_label = path === 2 ? 'distributor' : 'qualified';
const empresa = enrich.nome_fantasia || enrich.razao_social || extract.nome;

return [{
  json: {
    // Original form data
    facebook_lead_id: extract.facebook_lead_id,
    form_id: extract.form_id,
    page_id: extract.page_id,
    nome: extract.nome,
    email: extract.email,
    telefone_raw: extract.telefone_raw,
    telefone: phone.telefone,
    perfil: extract.perfil,
    volume_faixa: extract.volume_faixa,
    volume_numerico: volume_numerico,
    cnpj_raw: extract.cnpj_raw,
    cnpj: cnpjData.cnpj,
    estado_envio: extract.estado_envio,
    estado_uf: estado_uf,
    // Enrichment
    cnpj_valido: true,
    razao_social: enrich.razao_social || '',
    nome_fantasia: enrich.nome_fantasia || '',
    cnae: enrich.cnae || '',
    cnpj_city: enrich.city || '',
    cnpj_state: enrich.state || '',
    // Classification
    path: path,
    path_reason: path_reason,
    path_label: path_label,
    empresa: empresa,
    isNNE: isNNE
  }
}];

