const cl = $('Classify Lead').first().json;
const convId = $('Create Conversation').first().json.id || '';
const fbLeadId = $('Save fb_lead').first().json.id || '';
const dists = $input.all();

let contactId = 0;
try { contactId = $('Extract New Contact').first().json.contact_id; } catch (e) {}
try { contactId = $('Use Existing Contact').first().json.contact_id; } catch (e) {}

const nome = (cl.nome || '').trim().split(' ')[0] || cl.nome || 'cliente';
const empresa = cl.empresa || cl.razao_social || cl.nome_fantasia || '';
const estado = cl.estado_envio || '';
const volumeFaixa = cl.volume_faixa || '';
const volumeNumerico = Number(cl.volume_numerico || 0);
const isLowVolume = volumeNumerico > 0 && volumeNumerico < 4000;

const distributors_json = dists.length > 0 && dists[0].json.razao_social
  ? dists.map((d) => ({
      id: d.json.id,
      razao_social: d.json.razao_social,
      cidade: d.json.cidade,
      telefone: d.json.telefone || null,
    }))
  : [];

const hasDistributors = distributors_json.length > 0;
const listaDistribuidores = hasDistributors
  ? distributors_json.map((d, i) => {
      const fone = d.telefone ? `\n   Tel: ${d.telefone}` : '';
      return `${i + 1}. *${d.razao_social}* - ${d.cidade}${fone}`;
    }).join('\n\n')
  : '';

const abertura = `Ola ${nome}! Aqui e o Joao da ASX Iluminacao. 👋\n\nVi que a *${empresa}* se cadastrou pelo nosso formulario para conhecer nossos produtos.`;

let justificativa = '';
if (isLowVolume) {
  justificativa = `Pelo volume mensal informado no cadastro (*${volumeFaixa}*), o canal mais adequado neste momento e o atendimento pelos nossos distribuidores parceiros, que conseguem te atender com mais agilidade.`;
} else {
  justificativa = 'Para atendimento comercial direto, nossa operacao hoje prioriza negocios nas regioes Norte e Nordeste. Para a sua localidade, o canal mais adequado e o atendimento pelos nossos distribuidores parceiros.';
}

const blocoDistribuidores = hasDistributors
  ? `Na sua regiao, recomendo:\n\n${listaDistribuidores}`
  : `No momento, nao encontrei um distribuidor ativo da ASX cadastrado para *${estado}*. Estou registrando internamente o seu interesse para acompanhamento da nossa rede.`;

const fechamento = 'Voce tambem pode consultar todos os nossos distribuidores em: asx.com.br/distribuidores\n\nQualquer duvida, estou por aqui!';

const message = [abertura, justificativa, blocoDistribuidores, fechamento]
  .filter(Boolean)
  .join('\n\n');

return [{
  json: {
    message,
    phone: cl.telefone,
    distributors_json,
    fb_lead_id: fbLeadId,
    contact_id: contactId,
    conversation_id: convId,
  }
}];

const cl = $('Classify Lead').first().json;
const convId = $('Create Conversation').first().json.id || '';
const fbLeadId = $('Save fb_lead').first().json.id || '';

let contactId = 0;
try { contactId = $('Extract New Contact').first().json.contact_id; } catch(e) {}
try { contactId = $('Use Existing Contact').first().json.contact_id; } catch(e) {}

const nome = cl.nome.split(' ')[0];
const empresa = cl.empresa || cl.razao_social || cl.nome_fantasia || '';
const perfil = cl.perfil;
const volume = cl.volume_faixa;
const estado = cl.estado_envio;

const message = `Ola ${nome}! Aqui e o Joao, consultor comercial da ASX Iluminacao.\n\nVi que a *${empresa}* se cadastrou para negociacao direta conosco. Que otimo saber do seu interesse!\n\nConfirmei aqui seus dados do cadastro:\n• Perfil: ${perfil}\n• Volume mensal: ${volume}\n• Estado: ${estado}\n\nEsta tudo certo? Posso dar andamento ao seu atendimento?`;

return [{
  json: {
    message: message,
    phone: cl.telefone,
    fb_lead_id: fbLeadId,
    contact_id: contactId,
    conversation_id: convId
  }
}];
